// quicksort sorts s[lo..hi] in place using a Lomuto partition around s[hi].
func quicksort(s []int, lo, hi int) {
	if lo >= hi {
		return
	}
	pivot := s[hi]
	i := lo
	for j := lo; j < hi; j++ {
		if s[j] < pivot {
			s[i], s[j] = s[j], s[i]
			i++
		}
	}
	s[i], s[hi] = s[hi], s[i] // put pivot in its final place
	quicksort(s, lo, i-1)
	quicksort(s, i+1, hi)
}

func main() {
	s := []int{5, 2, 9, 1, 5, 6}
	quicksort(s, 0, len(s)-1)
	fmt.Println(s) // [1 2 5 5 6 9]
}
