package main

import (
	"fmt"
	"time"
)

func main() {
	result := make(chan string, 1) // buffered so the goroutine never leaks
	go func() {
		time.Sleep(20 * time.Millisecond)
		result <- "done"
	}()

	select {
	case r := <-result:
		fmt.Println("got:", r)
	case <-time.After(50 * time.Millisecond):
		fmt.Println("timed out")
	}
}
